spec.fn:
check_in = flow['input']['check_in']
check_out = flow['input']['check_out']
room_type = flow['input']['room_type']
location = flow['input']['location']
total_guests = flow['input']['total_guests']

details = f"Here are the details. Check in {check_in}, check out {check_out}. With a {room_type} type room in {location} for {total_guests} guests"

message_to_human_agent = f"User would like to book a room. {details}"

message_to_chatter = f"I'll transfer you to an agent to book your room."

flow.output.content = [
    {
        "type": "text",
        "text": message_to_chatter,
        "annotations": {"audience": ["user"]}
    }
]


flow.output._meta =  {
