      "agent_available": "Agent is available.",
      "transfer_metadata": {
          "reason" : "Book a hotel",
          "summary" : message_to_human_agent,
          "disconnection_reason" : None,
          "queue_name" : "hotel_booking_queue"
      },
      "service_desk_info": {
        "sip": {
          "uri": "tel:+1xxx",
          "transfer_method": "refer"
        }
      }
    }
  }
}
